#include <cstdio>
#include <omp.h>

#define N 1000000
#define RADIUS 3

void stencil_1d(const float *in, float *out, int n) {
    #pragma omp parallel for
    for (int i = RADIUS; i < n - RADIUS; i++) {
        float result = 0.0f;
        for (int j = -RADIUS; j <= RADIUS; j++) {
            result += in[i + j];
        }
        out[i] = result / (2 * RADIUS + 1);
    }
}

int main() {
    float *in = new float[N];
    float *out = new float[N];

    // Initialize input data
    for (int i = 0; i < N; i++) {
        in[i] = i * 1.0f;
        out[i] = 0.0f;
    }

    stencil_1d(in, out, N);

    // Print some output for verification
    for (int i = RADIUS; i < RADIUS + 10; i++) {
        printf("out[%d] = %f\n", i, out[i]);
    }

    delete[] in;
    delete[] out;

    return 0;
}
